const client = $input.first().json;

const services = Array.isArray(client.services)
  ? client.services.join(', ')
  : (client.services || '');

const goals = Array.isArray(client.posting_goals)
  ? client.posting_goals.join(', ')
  : '';

const colors = (typeof client.brand_colors === 'object' && client.brand_colors)
  ? client.brand_colors
  : {};

const primary   = colors.primary   || '#000000';
const secondary = colors.secondary || '#ffffff';
const imageStyle = client.image_style || 'cinematic';
const location   = client.location  || '';

const toneGuide = {
  professional:  'polished, authoritative — short declarative sentences, no contractions',
  casual:        'conversational, warm — use contractions, ask rhetorical questions',
  premium:       'aspirational, exclusive — sensory and transformational language',
  playful:       'energetic, fun — light humour, punchy short sentences',
  bold:          'direct, zero-fluff — imperatives, no hedging words',
  inspirational: 'motivational, uplifting — speak to who the reader wants to become'
};
const tone = toneGuide[client.tone_of_voice] || client.tone_of_voice;

const contentTypes = ['educational','authority','social_proof','problem_solution','behind_the_scenes'];
const hookStyles   = ['curiosity','problem','warning','authority','local'];

const assignments = Array.from({length: 5}, (_, i) => ({
  num: i + 1,
  content_type: contentTypes[i],
  hook_style:   hookStyles[i]
})).map(a => `  Post ${a.num}: content_type=${a.content_type}, hook_style=${a.hook_style}`).join('
');

const localCtx = location
  ? `Local context: Reference ${location} market realities naturally.`
  : '';

const systemPrompt = `You are an elite viral social media copywriter. You write for humans — authentic, emotional, direct.
BANNED: "we are proud to announce", "game-changing", "synergy", "leverage", "seamless", "cutting-edge".
NO two hooks start with the same word. NO two CTAs use the same verb. NO two posts share the same emotional trigger.
Output ONLY valid JSON. No markdown. No code fences.`;

const userPrompt = `Generate exactly 5 viral social media posts.

CLIENT:
- Name: ${client.name}
- Industry: ${client.industry}
- Services: ${services}
- Tone: ${client.tone_of_voice} (${tone})
- Audience: ${client.target_audience || 'general audience'}
- Location: ${location || 'not specified'}
- Goals: ${goals}
- Brand Colors: Primary ${primary} / Secondary ${secondary}
- Image Style: ${imageStyle}

POST ASSIGNMENTS:
${assignments}

HOOK STYLES:
- curiosity: "Most [audience] don't know this about..." — open a loop
- problem: "Tired of [specific pain]?" — make them feel seen
- warning: "This mistake could be costing you [consequence]..." — create urgency
- authority: "After [X years/clients] in [industry]..." — lead with credentials
- local: Hyper-local opening specific to ${location || 'the client location'}

CAPTION STRUCTURE (3 beats, blank line between each):
  Beat 1: Deliver on the hook promise
  Beat 2: Core value, insight, or story
  Beat 3: Bridge naturally to the CTA

EMOTIONAL TRIGGERS — use each once across 5 posts: trust, urgency, curiosity, authority, aspiration

CTA VERBS — no repeats: comment / DM / book / share / call / tag / visit / save / reply / click

HASHTAGS — 6-9 per post: 2 broad industry + 3-4 niche + 1-2 local (if location exists)

IMAGE PROMPT — all 6 elements required:
"${imageStyle} photo of [subject], [environment], [lighting], ${primary}/${secondary} in [element], [angle], DSLR, 4K, photorealistic, no text"

${localCtx}

Return ONLY this JSON:
{
  "posts": [
    {
      "content_type": "educational",
      "hook": "...",
      "caption": "...",
      "emotional_trigger": "curiosity",
      "call_to_action": "...",
      "hashtags": ["#tag1"],
      "image_prompt": "..."
    }
  ]
}`;

return [{
  json: {
    client_id: client.id,
    client,
    systemPrompt,
    userPrompt
  }
}];

const response = $input.first().json;
const clientId = $('Build Prompt').first().json.client_id;

let posts = [];
try {
  const raw = response.choices[0].message.content;
  const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
  posts = parsed.posts || parsed;
  if (!Array.isArray(posts)) posts = [];
} catch (e) {
  // Return a fallback post so the workflow doesn't die
  return [{
    json: {
      client_id: clientId,
      hook: 'Content generation is temporarily unavailable.',
      caption: 'Please try again shortly.',
      emotional_trigger: 'trust',
      call_to_action: 'Contact us directly.',
      hashtags: [],
      image_prompt: 'professional business photo, clean office environment, natural lighting',
      content_type: 'educational',
      is_fallback: true
    }
  }];
}

if (posts.length === 0) {
  return [{ json: { error: 'No posts returned from model', client_id: clientId } }];
}

// Inject client_id into every post for downstream access
return posts.map(post => ({
  json: {
    client_id: clientId,
    hook:              post.hook              || '',
    caption:           post.caption           || '',
    emotional_trigger: post.emotional_trigger || null,
    call_to_action:    post.call_to_action    || '',
    hashtags:          Array.isArray(post.hashtags) ? post.hashtags : [],
    image_prompt:      post.image_prompt      || '',
    content_type:      post.content_type      || null
  }
}));

const response = $input.first().json;
const post     = $('Preserve Post').first().json;

let imageUrl = null;
try {
  const message = response.choices[0].message;
  // Gemini returns image in message.images[]
  if (Array.isArray(message.images) && message.images.length > 0) {
    imageUrl = message.images[0]?.image_url?.url || null;
  }
  // Fallback: image embedded in content array
  if (!imageUrl && Array.isArray(message.content)) {
    for (const block of message.content) {
      if (block.type === 'image_url') {
        imageUrl = block.image_url?.url || null;
        break;
      }
    }
  }
} catch (e) {
  // imageUrl stays null — post is still valid without image
}

return [{
  json: {
    client_id:        post.client_id,
    hook:             post.hook,
    caption:          post.caption,
    emotional_trigger:post.emotional_trigger,
    call_to_action:   post.call_to_action,
    hashtags:         post.hashtags,
    image_prompt:     post.image_prompt,
    content_type:     post.content_type,
    image_url:        imageUrl
  }
}];

const allItems = $input.all();
const posts = allItems.map(i => i.json);
const clientId = posts[0]?.client_id || '';

// Strip internal client_id from each post before saving
const cleanPosts = posts.map(p => ({
  hook:              p.hook,
  caption:           p.caption,
  emotional_trigger: p.emotional_trigger,
  call_to_action:    p.call_to_action,
  hashtags:          p.hashtags || [],
  image_prompt:      p.image_prompt,
  content_type:      p.content_type,
  image_url:         p.image_url || null
}));

return [{
  json: {
    client_id: clientId,
    posts: cleanPosts
  }
}];
